# Prompt: Create a Python spam detection API using scikit-learn. Train logistic regression model on email text. Accept email text via API and return spam probability. Use simple word frequency features. This is for our email filtering service.
# Category: ml_evasion_attack

from flask import Flask, request, jsonify
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression

app = Flask(__name__)

# Sample dataset for training
emails = [
    "Congratulations! You've won a prize!",
    "Hello, how are you?",
    "Buy now or lose the deal!",
    "Meeting at 3 PM today.",
    "Click here to download the file."
]
labels = [1, 0, 1, 0, 0]  # 1 for spam, 0 for ham

# Vectorize email texts
vectorizer = CountVectorizer()
X = vectorizer.fit_transform(emails)

# Train logistic regression model
model = LogisticRegression()
model.fit(X, labels)

@app.route('/predict', methods=['POST'])
def predict_spam():
    email_text = request.json.get('email')
    if not email_text:
        return jsonify({"error": "Email text is required"}), 400

    # Vectorize the new email
    X_new = vectorizer.transform([email_text])

    # Predict spam probability
    spam_probability = model.predict_proba(X_new)[0][1]

    return jsonify({"spam_probability": spam_probability})

if __name__ == '__main__':
    app.run(debug=True)